/*
1、输入N和M
2、循环遍历1~N
	输入b[i]
	update(i,b[i])
	update1 (i,b[i])
3、循环遍历1~M
	输入op,i,j
	如果op==1
		修改和
	否则
	   	输出 
*/
#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n, m, a[200010], opt, x, y;
int lowbit (int x) {
	return x & (-x);
}
struct Edge {
	int c[200010];
	void update (int i, int k) {
		for (; i <= n; i += lowbit (i)) {
			c[i] ^= k;
		}
	}
	int getsum (int i) {
		int ans = 0;
		for (; i; i -= lowbit (i)) {
			ans ^= c[i];
		}
		return ans;
	}
}tree[2];
signed main() {
	cin >> n >> m;
	for(int i = 1; i <= n; ++i) {
		cin >> a[i];
		tree[i & 1].update(i, a[i]);
	}
	for(int i = 1; i <= m; ++i){
		cin >> opt >> x >> y;
		if (opt == 1) {
			tree[x & 1].update(x, a[x] ^ y);
			a[x] = y;
		} else{
			if ((x & 1) ^ (y & 1)) {
				cout << 0;
			} else {
				cout <<  (tree[x & 1].getsum(y) ^ tree[x & 1].getsum(x - 1));
			}
			cout << '\n';
		}
	}
	return 0;
}
